    15→inception-engine - Deploy AI agent skills
    16→
    17→Usage:
    18→  inception-engine <directory> [options]
    19→  inception-engine revert <directory> [options]
    20→
    21→Options:
    22→  --dry-run        Show what would be done without doing it
    23→  --agents <list>  Comma-separated list of agent IDs to target
    24→  --verbose        Show detailed output
    25→  --debug          Show full error stack traces
    26→  --help           Show this help message
    27→
    28→Supported agents:
    29→  ${AGENT_REGISTRY.map((a) => `${a.id} (${a.displayName})`).join(", ")}
    30→`.trim();
    31→
    32→function parseArgs(argv: string[]): CliOptions {
    33→  const args = argv.slice(2);
    34→
    35→  if (args.length === 0 || args.includes("--help")) {
    36→    return { command: "help", directory: "", dryRun: false, agents: null, verbose: false, debug: false };
    37→  }
    38→
    39→  let command: "deploy" | "revert" = "deploy";
    40→  let directory = "";
    41→  let dryRun = false;
    42→  let agents: AgentId[] | null = null;
    43→  let verbose = false;
    44→  let debug = false;
    45→
    46→  let i = 0;
