    58→      verbose = true;
    59→    } else if (arg === "--debug") {
    60→      debug = true;
    61→    } else if (arg === "--agents") {
    62→      i++;
    63→      const next = args[i];
    64→      if (!next) {
    65→        throw new UserError("--agents requires a comma-separated list");
    66→      }
    67→      const ids = next.split(",").map((s) => s.trim());
    68→      for (const id of ids) {
    69→        if (!AGENT_IDS.includes(id as AgentId)) {
    70→          throw new UserError(`Unknown agent: "${id}". Valid agents: ${AGENT_IDS.join(", ")}`);
    71→        }
    72→      }
    73→      agents = ids as AgentId[];
    74→    } else if (arg.startsWith("--")) {
    75→      throw new UserError(`Unknown option: ${arg}`);
    76→    } else if (!directory) {
    77→      directory = arg;
    78→    } else {
    79→      throw new UserError(`Unexpected argument: ${arg}`);
    80→    }
    81→    i++;
    82→  }
    83→
    84→  if (!directory) {
    85→    throw new UserError("Missing required <directory> argument");
    86→  }
    87→
    88→  return { command, directory: path.resolve(directory), dryRun, agents, verbose, debug };
    89→}
