   163→  if (err instanceof UserError) {
   164→    console.error(`Error: ${err.message}`);
   165→  } else {
   166→    console.error("Unexpected error. Run with --debug for details.");
   167→  }
   168→  if (debugMode) {
   169→    console.error(err);
   170→  }
   171→  process.exit(1);
   172→}
